import React, { useState } from 'react';

function Pane({ title, items, checked, onToggle }) {
  return (
    <div style={{ flex: 1, border: '1px solid #ddd', borderRadius: 8, minHeight: 180 }}>
      <div style={{ padding: '8px 12px', borderBottom: '1px solid #eee', fontWeight: 600 }}>{title}</div>
      <ul style={{ listStyle: 'none', margin: 0, padding: 4 }}>
        {items.map((i) => (
          <li key={i.id}>
            <label style={{ display: 'flex', gap: 8, padding: '6px 8px', cursor: 'pointer', borderRadius: 6, background: checked.has(i.id) ? '#eef2ff' : 'transparent' }}>
              <input type="checkbox" checked={checked.has(i.id)} onChange={() => onToggle(i.id)} />
              {i.label}
            </label>
          </li>
        ))}
        {items.length === 0 && <li style={{ color: '#aaa', padding: '6px 8px' }}>(empty)</li>}
      </ul>
    </div>
  );
}

export default function TransferList({ initialLeft, initialRight }) {
  const [left, setLeft] = useState(initialLeft);
  const [right, setRight] = useState(initialRight);
  const [checked, setChecked] = useState(() => new Set());

  const toggle = (id) =>
    setChecked((s) => {
      const n = new Set(s);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });

  const moveRight = () => {
    const moving = left.filter((i) => checked.has(i.id));
    setRight((r) => [...r, ...moving]);
    setLeft((l) => l.filter((i) => !checked.has(i.id)));
    setChecked(new Set());
  };

  const moveLeft = () => {
    const moving = right.filter((i) => checked.has(i.id));
    setLeft((l) => [...l, ...moving]);
    setRight((r) => r.filter((i) => !checked.has(i.id)));
    setChecked(new Set());
  };

  const leftChecked = left.some((i) => checked.has(i.id));
  const rightChecked = right.some((i) => checked.has(i.id));

  const btn = { padding: '6px 12px', cursor: 'pointer', borderRadius: 6 };

  return (
    <div style={{ display: 'flex', gap: 12, alignItems: 'center', maxWidth: 520 }}>
      <Pane title="Available" items={left} checked={checked} onToggle={toggle} />
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        <button style={{ ...btn, opacity: leftChecked ? 1 : 0.4 }} disabled={!leftChecked} onClick={moveRight} aria-label="Move right">›</button>
        <button style={{ ...btn, opacity: rightChecked ? 1 : 0.4 }} disabled={!rightChecked} onClick={moveLeft} aria-label="Move left">‹</button>
      </div>
      <Pane title="Selected" items={right} checked={checked} onToggle={toggle} />
    </div>
  );
}

