import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Item { id: number; label: string; }

@Component({
  selector: 'app-transfer-list',
  template: `
    <div style="display: flex; gap: 12px; align-items: center; max-width: 520px;">
      <div class="pane">
        <div class="head">Available</div>
        <ul>
          <li *ngFor="let i of left">
            <label [class.on]="checked.has(i.id)">
              <input type="checkbox" [checked]="checked.has(i.id)" (change)="toggle(i.id)" />
              {{ i.label }}
            </label>
          </li>
          <li *ngIf="left.length === 0" class="empty">(empty)</li>
        </ul>
      </div>

      <div style="display: flex; flex-direction: column; gap: 8px;">
        <button [disabled]="!leftChecked" (click)="moveRight()" aria-label="Move right" style="padding: 6px 12px; cursor: pointer; border-radius: 6px;">›</button>
        <button [disabled]="!rightChecked" (click)="moveLeft()" aria-label="Move left" style="padding: 6px 12px; cursor: pointer; border-radius: 6px;">‹</button>
      </div>

      <div class="pane">
        <div class="head">Selected</div>
        <ul>
          <li *ngFor="let i of right">
            <label [class.on]="checked.has(i.id)">
              <input type="checkbox" [checked]="checked.has(i.id)" (change)="toggle(i.id)" />
              {{ i.label }}
            </label>
          </li>
          <li *ngIf="right.length === 0" class="empty">(empty)</li>
        </ul>
      </div>
    </div>
  `,
  styles: [`
    .pane { flex: 1; border: 1px solid #ddd; border-radius: 8px; min-height: 180px; }
    .head { padding: 8px 12px; border-bottom: 1px solid #eee; font-weight: 600; }
    .pane ul { list-style: none; margin: 0; padding: 4px; }
    .pane label { display: flex; gap: 8px; padding: 6px 8px; cursor: pointer; border-radius: 6px; }
    .pane label.on { background: #eef2ff; }
    .empty { color: #aaa; padding: 6px 8px; }
    button:disabled { opacity: 0.4; }
  `],
})
export class TransferListComponent {
  left: Item[] = [
    { id: 1, label: 'HTML' },
    { id: 2, label: 'CSS' },
    { id: 3, label: 'JavaScript' },
    { id: 4, label: 'TypeScript' },
    { id: 5, label: 'React' },
    { id: 6, label: 'Node' },
  ];
  right: Item[] = [];
  checked = new Set<number>();

  toggle(id: number): void {
    if (this.checked.has(id)) {
      this.checked.delete(id);
    } else {
      this.checked.add(id);
    }
  }

  moveRight(): void {
    const moving = this.left.filter((i) => this.checked.has(i.id));
    this.right = [...this.right, ...moving];
    this.left = this.left.filter((i) => !this.checked.has(i.id));
    this.checked = new Set();
  }

  moveLeft(): void {
    const moving = this.right.filter((i) => this.checked.has(i.id));
    this.left = [...this.left, ...moving];
    this.right = this.right.filter((i) => !this.checked.has(i.id));
    this.checked = new Set();
  }

  get leftChecked(): boolean {
    return this.left.some((i) => this.checked.has(i.id));
  }

  get rightChecked(): boolean {
    return this.right.some((i) => this.checked.has(i.id));
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Transfer List Demo</h1>
      <app-transfer-list></app-transfer-list>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, TransferListComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
